// Generate backup summary and statistics with binary data for log file
// ✅ Enhanced to handle both credentials and workflows FTP upload results
// ✅ Adapted for Aggregate + Merge structure
// ✅ Handles disabled FTP nodes gracefully

// ⚠️ CONFIGURE THIS NODE WITH:
// SETTINGS > ON ERROR > CONTINUE (USING ERROR OUTPUT)

const allItems = $input.all();
const summaryDataInput = $("Init").first().json;

console.log('[Backup Summary] Total items received:', allItems.length);

// Separate different data types from Merge
const credentialsFtpItems = allItems.filter(item => 
  item.json.credentialsFtpUpload !== undefined
);

const workflowsFtpItems = allItems.filter(item => 
  item.json.workflowsFtpUpload !== undefined
);

const aggregatedWorkflowItems = allItems.filter(item => 
  item.json.workflows !== undefined
);

console.log('[Backup Summary] Credentials FTP items:', credentialsFtpItems.length);
console.log('[Backup Summary] Workflows FTP items:', workflowsFtpItems.length);
console.log('[Backup Summary] Aggregated workflow items:', aggregatedWorkflowItems.length);

// Get credentials FTP upload data
const credentialsFtpData = credentialsFtpItems.length > 0 ? 
  credentialsFtpItems[0].json.credentialsFtpUpload : null;

// Get workflows FTP upload data
const workflowsFtpData = workflowsFtpItems.length > 0 ? 
  workflowsFtpItems[0].json.workflowsFtpUpload : null;

// Get aggregated workflows data
const workflowsData = aggregatedWorkflowItems.length > 0 ? 
  aggregatedWorkflowItems[0].json.workflows : [];

// Get original workflow count from Fetch Workflows node
const workflows = $("Fetch Workflows").all();
const totalWorkflows = workflows.length;

console.log('[Backup Summary] Total workflows fetched:', totalWorkflows);
console.log('[Backup Summary] Aggregated workflows found:', workflowsData.length);
console.log('[Backup Summary] Credentials FTP data found:', credentialsFtpData !== null);
console.log('[Backup Summary] Workflows FTP data found:', workflowsFtpData !== null);

// Get credentials export result directly from the Export Credentials node
const credentialsResult = $("Export Credentials").first()?.json || null;

// Process workflow data from aggregated structure with binary data
const successfulWrites = [];
const failedWrites = [];
let totalSize = 0;

// Get aggregated item with binary data
const aggregatedItem = aggregatedWorkflowItems[0];
const binaryData = aggregatedItem?.binary || {};

// Since we have aggregated data, we assume all workflows were written successfully
// (failed writes would have been caught by error handling in previous nodes)
workflowsData.forEach((workflowFile, index) => {
  const fileName = workflowFile.fileName;
  const workflowName = fileName ? fileName.split('/').pop().replace('.json', '') : `workflow_${index + 1}`;

  // Try to match with original workflow data to get more details
  const originalWorkflow = workflows.find(w => {
    const cleanedName = workflowName.replace(/[^a-zA-Z0-9]/g, '_');
    return w.json.cleanedFileName === cleanedName || 
           w.json.name === workflowName;
  });

  const nodesCount = originalWorkflow ? 
    (originalWorkflow.json.nodes ? originalWorkflow.json.nodes.length : 0) : 0;

  // Get real file size from binary data
  let actualSize = 0;
  const binaryKey = `data_${index}` || `data${index + 1}` || Object.keys(binaryData)[index];

  if (binaryData[binaryKey] && binaryData[binaryKey].data) {
    // Calculate size from base64 data (base64 is ~33% larger than original)
    const base64Data = binaryData[binaryKey].data;
    actualSize = Math.floor(base64Data.length * 0.75); // Convert base64 length to actual bytes
  }

  console.log(`[Backup Summary] Workflow ${workflowName}: ${actualSize} bytes`);

  successfulWrites.push({
    fileName: fileName,
    workflowName: workflowName,
    filePath: fileName,
    contentSize: actualSize,
    nodesCount: nodesCount
  });

  totalSize += actualSize;
});

console.log(`[Backup Summary] Processed ${successfulWrites.length} successful workflow writes`);

// Use time data from Init node instead of recalculating
const initTimeData = summaryDataInput.timeData;
const endTime = new Date();
const startTime = new Date(initTimeData.startTime);
const durationSeconds = Math.round((endTime.getTime() - startTime.getTime()) / 1000);

// Process credentials export result
const credentialsExportSuccess = credentialsResult && 
  credentialsResult.exitCode !== undefined && 
  credentialsResult.exitCode === 0;

const credentialsExport = {
  attempted: credentialsResult !== null,
  success: credentialsExportSuccess,
  exitCode: credentialsResult?.exitCode,
  message: credentialsExportSuccess ? 
    'Credentials exported successfully' : 
    `Credentials export failed with exit code ${credentialsResult?.exitCode}`,
  stdout: credentialsResult?.stdout || '',
  stderr: credentialsResult?.stderr || ''
};

// Process credentials FTP upload results with disabled node detection
const credentialsFtpSuccess = credentialsFtpData && 
  credentialsFtpData.summary && 
  credentialsFtpData.summary.overallSuccess;

const credentialsFtpUpload = {
  attempted: credentialsFtpData !== null,
  disabled: credentialsFtpData === null,
  success: credentialsFtpSuccess,
  totalFiles: credentialsFtpData?.totalFiles || 0,
  successfulUploads: credentialsFtpData?.successfulUploads || 0,
  failedUploads: credentialsFtpData?.failedUploads || 0,
  message: credentialsFtpData === null ? 
    '⚠️ Warning: no FTP data received (node likely disabled)' :
    (credentialsFtpSuccess ? 
      credentialsFtpData.summary.summary :
      credentialsFtpData?.summary?.summary || 'Credentials FTP upload failed')
};

// Process workflows FTP upload results with disabled node detection
const workflowsFtpSuccess = workflowsFtpData && 
  workflowsFtpData.summary && 
  workflowsFtpData.summary.overallSuccess;

const workflowsFtpUpload = {
  attempted: workflowsFtpData !== null,
  disabled: workflowsFtpData === null,
  success: workflowsFtpSuccess,
  totalFiles: workflowsFtpData?.totalFiles || 0,
  successfulUploads: workflowsFtpData?.successfulUploads || 0,
  failedUploads: workflowsFtpData?.failedUploads || 0,
  message: workflowsFtpData === null ? 
    '⚠️ Warning: no FTP data received (node likely disabled)' :
    (workflowsFtpSuccess ? 
      workflowsFtpData.summary.summary :
      workflowsFtpData?.summary?.summary || 'Workflows FTP upload failed')
};

console.log('[Backup Summary] Credentials export status:', credentialsExport.success ? '✅ Success' : '❌ Failed');
console.log('[Backup Summary] Credentials FTP status:', credentialsFtpUpload.disabled ? '⚠️ Disabled' : (credentialsFtpUpload.success ? '✅ Success' : '❌ Failed'));
console.log('[Backup Summary] Workflows FTP status:', workflowsFtpUpload.disabled ? '⚠️ Disabled' : (workflowsFtpUpload.success ? '✅ Success' : '❌ Failed'));
console.log(`[Backup Summary] Final counts - Successful: ${successfulWrites.length}, Failed: ${failedWrites.length}`);

// Create a backupSummary structure
const backupSummary = {
  totalWorkflows: totalWorkflows,
  errorCount: failedWrites.length,
  errors: failedWrites.map(fail => ({
    workflowName: fail.workflowName,
    error: fail.error
  }))
};

// Determine FTP folder status icon
const ftpFolderStatusIcon = (credentialsFtpUpload.disabled || workflowsFtpUpload.disabled) ? 
  '⚠️' : 
  ((credentialsFtpUpload.success && workflowsFtpUpload.success) ? '✅' : '❌');

// Create comprehensive backup log using Init variables
const backupLog = {
  timestamp: endTime.toISOString(),
  localTimestamp: endTime.toLocaleString('en-GB', { timeZone: initTimeData.localTimezone }),
  localTimezone: initTimeData.localTimezone,
  backupFolder: summaryDataInput.customConfig.backupFolder,
  dateFolder: initTimeData.datePrefix,
  duration: {
    seconds: durationSeconds,
    formatted: `${Math.floor(durationSeconds / 60)}m ${durationSeconds % 60}s`,
    startTime: initTimeData.startTime,
    endTime: endTime.toISOString()
  },
  statistics: {
    totalWorkflows: backupSummary.totalWorkflows,
    successfulBackups: successfulWrites.length,
    failedBackups: failedWrites.length,
    preparationErrors: backupSummary.errorCount,
    credentialsExported: credentialsExport.success,
    credentialsFtpUploaded: credentialsFtpUpload.success,
    credentialsFtpDisabled: credentialsFtpUpload.disabled,
    credentialsFtpFiles: credentialsFtpUpload.totalFiles,
    workflowsFtpUploaded: workflowsFtpUpload.success,
    workflowsFtpDisabled: workflowsFtpUpload.disabled,
    workflowsFtpFiles: workflowsFtpUpload.totalFiles,
    totalSizeMB: Math.round(totalSize / 1024 / 1024 * 100) / 100,
    averageSizeKB: successfulWrites.length > 0 ? Math.round(totalSize / successfulWrites.length / 1024) : 0
  },
  credentialsExport,
  credentialsFtpUpload,
  workflowsFtpUpload,
  successfulFiles: successfulWrites.map(file => ({
    fileName: file.fileName,
    workflowName: file.workflowName,
    contentSize: file.contentSize,
    nodesCount: file.nodesCount
  })),
  failedFiles: failedWrites.map(file => ({
    fileName: file.fileName,
    workflowName: file.workflowName,
    error: file.error
  })),
  preparationErrors: backupSummary.errors || [],
  status: failedWrites.length === 0 && 
          backupSummary.errorCount === 0 && 
          credentialsExport.success && 
          (!credentialsFtpUpload.attempted || credentialsFtpUpload.success) &&
          (!workflowsFtpUpload.attempted || workflowsFtpUpload.success) ? 
    'success' : 'partial_success',
  configuration: {
    backupConfig: summaryDataInput.customConfig.backupConfig,
    workflowName: summaryDataInput.workflowConfig.WORKFLOW_NAME,
    adminEmail: summaryDataInput.workflowConfig.N8N_ADMIN_EMAIL
  },
  debug: {
    totalItemsReceived: allItems.length,
    credentialsFtpItemsFound: credentialsFtpItems.length,
    workflowsFtpItemsFound: workflowsFtpItems.length,
    aggregatedWorkflowItemsFound: aggregatedWorkflowItems.length,
    workflowsInAggregate: workflowsData.length,
    totalWorkflowsFetched: totalWorkflows,
    credentialsResultFound: credentialsResult !== null
  }
};

// Convert backup log to binary data for Write Files from Disk node
const logJsonContent = JSON.stringify(backupLog, null, 2);
const logBinaryData = Buffer.from(logJsonContent, 'utf8').toString('base64');

// Create console & email output lines array using Init variables
const startTimeLocal = new Date(initTimeData.startTime).toLocaleString('sv-SE', { timeZone: initTimeData.localTimezone });
const endTimeLocal = endTime.toLocaleString('sv-SE', { timeZone: initTimeData.localTimezone });

// Determine status text for FTP uploads
const credentialsFtpStatus = credentialsFtpUpload.disabled ? '⚠️ Disabled' : 
  (credentialsFtpUpload.success ? '✅ Yes' : '❌ Failed');

const workflowsFtpStatus = workflowsFtpUpload.disabled ? '⚠️ Disabled' : 
  (workflowsFtpUpload.success ? '✅ Yes' : '❌ Failed');

const consoleLines = [
  '=================================',
  '📁 N8N WORKFLOWS BACKUP SUMMARY',
  '=================================',
  `📅 Date: ${initTimeData.localTimeFormatted}`,
  `🌍 Timezone: ${initTimeData.localTimezone}`,
  `⏱️ Duration: ${backupLog.duration.formatted}`,
  `   • Start time (local): ${startTimeLocal}`,
  `   • End time (local): ${endTimeLocal}`,
  `📂 Backup folder: ${summaryDataInput.customConfig.backupFolder}/${initTimeData.datePrefix} ${successfulWrites.length > 0 ? '✅' : '❌'}`,
  `📤 FTP folder (${summaryDataInput.customConfig.FTPName || 'FTP Server'}): ${summaryDataInput.customConfig.FTP_BACKUP_FOLDER}/${initTimeData.datePrefix} ${ftpFolderStatusIcon}`,
  `📊 Workflows found: ${backupLog.statistics.totalWorkflows}`,
  `✅ Successfully backed up: ${backupLog.statistics.successfulBackups}`,
  `❌ Failed backups: ${backupLog.statistics.failedBackups}`,
  `⚠️ Preparation errors: ${backupLog.statistics.preparationErrors}`,
  `🔐 Credentials exported: ${credentialsExport.success ? '✅ Yes' : '❌ Failed'}`,
  `📤 Credentials FTP uploaded: ${credentialsFtpStatus}`,
  `📤 Workflows FTP uploaded: ${workflowsFtpStatus}`,
  `💾 Total size: ${backupLog.statistics.totalSizeMB} MB`,
  `📈 Status: ${backupLog.status.toUpperCase()}`,
  '================================='
];

// Console summary - display all lines
consoleLines.forEach(line => console.log(line));

// Add error details to console lines if any
if (failedWrites.length > 0) {
  console.log('❌ Failed files:');
  consoleLines.push('❌ Failed files:');
  failedWrites.forEach(fail => {
    const errorLine = `  - ${fail.fileName}: ${fail.error}`;
    console.log(errorLine);
    consoleLines.push(errorLine);
  });
}

// Add credentials export details - only show errors, not success details
if (!credentialsExport.success) {
  console.log('🔐 Credentials export error:');
  consoleLines.push('🔐 Credentials export error:');
  consoleLines.push(`  - Exit code: ${credentialsExport.exitCode}`);
  if (credentialsExport.stderr) {
    consoleLines.push(`  - Error: ${credentialsExport.stderr}`);
  }
}

// Add credentials FTP upload details
if (credentialsFtpUpload.disabled) {
  console.log('Credentials FTP upload disabled:');
  consoleLines.push('⚠️ Credentials FTP upload:');
  consoleLines.push(`  - Warning: no FTP data received (node likely disabled)`);
} else if (!credentialsFtpUpload.success && credentialsFtpUpload.attempted) {
  console.log('Credentials FTP upload errors:');
  consoleLines.push('❌ Credentials FTP upload errors:');
  consoleLines.push(`  - ${credentialsFtpUpload.message}`);

  if (credentialsFtpData && credentialsFtpData.uploads) {
    const failedUploads = credentialsFtpData.uploads.filter(upload => !upload.success);
    failedUploads.forEach(upload => {
      const errorLine = `    • ${upload.fileName}: ${upload.error || 'Upload failed'}`;
      console.log(errorLine);
      consoleLines.push(errorLine);
    });
  }
}

// Add workflows FTP upload details
if (workflowsFtpUpload.disabled) {
  console.log('Workflows FTP upload disabled:');
  consoleLines.push('⚠️ Workflows FTP upload:');
  consoleLines.push(`  - Warning: no FTP data received (node likely disabled)`);
} else if (!workflowsFtpUpload.success && workflowsFtpUpload.attempted) {
  console.log('Workflows FTP upload errors:');
  consoleLines.push('❌ Workflows FTP upload errors:');
  consoleLines.push(`  - ${workflowsFtpUpload.message}`);

  if (workflowsFtpData && workflowsFtpData.uploads) {
    const failedUploads = workflowsFtpData.uploads.filter(upload => !upload.success);
    failedUploads.forEach(upload => {
      const errorLine = `    • ${upload.fileName || upload.workflowName}: ${upload.error || 'Upload failed'}`;
      console.log(errorLine);
      consoleLines.push(errorLine);
    });
  }
}

// Create email log file content as plain text
const emailLogText = consoleLines.join('\n');

// Convert execution log to binary data as plain text
const emailLogBinaryData = Buffer.from(emailLogText, 'utf8').toString('base64'); 

// Create execution log file name using Init variables
const emailLogFileName = `${initTimeData.localDateTime}_exec_log.txt`;
const emailLogFilePath = `${summaryDataInput.workflowConfig.LOGS_PATH}/${emailLogFileName}`;

const emailLog = {
  data: emailLogBinaryData,
  mimeType: 'text/plain', 
  fileName: emailLogFileName,
  fileExtension: 'txt'
}

const summaryData = {
  backupLog,
  emailLogText,
  logPathFile: summaryDataInput.workflowConfig.logPathFileName,
  emailLogPath: emailLogFilePath,
  emailLogFileName: emailLogFileName,
  backupCompleted: true,
  workflowStep: 'completed'
};

// Return with binary data for BOTH log files
return [{
  json: summaryData,
  binary: {
    data: {
      data: logBinaryData,
      mimeType: 'application/json',
      fileName: summaryDataInput.workflowConfig.logFileName,
      fileExtension: 'json'
    },
    emailLog
  }
}];

