// Init Workflow Variables - Local timezone version
// ✅ All dates/times handled in local timezone

// ==========================================
// 📅 LOCAL DATE/TIME INITIALIZATION
// ==========================================

const now = new Date();

// ==========================================
// 🌍 USER-DEFINED TIMEZONE CONFIGURATION
// ==========================================
// ⚠️  IMPORTANT: This code runs on the n8n SERVER, not in your browser!
// ⚠️  Configure the timezone where you want executions to be scheduled,
// ⚠️  regardless of where your n8n server is physically located.
//
// 📍 Common timezone examples:
// - 'Europe/Paris'       → Central European Time (CET/CEST)
// - 'America/New_York'   → Eastern Time (EST/EDT)
// - 'America/Chicago'    → Central Time (CST/CDT)
// - 'America/Los_Angeles'→ Pacific Time (PST/PDT)
// - 'Asia/Tokyo'         → Japan Standard Time (JST)
// - 'Asia/Shanghai'      → China Standard Time (CST)
// - 'Australia/Sydney'   → Australian Eastern Time (AET)
// - 'UTC'                → Coordinated Universal Time
//
// 🔧 TO CONFIGURE FOR YOUR USE CASE:
// 1. Uncomment and edit the line below with your desired timezone
// 2. Comment out the automatic detection line
//
// To use user-defined timezone instead, UNCOMMENT these lines:
// const USER_TIMEZONE = 'Europe/Paris';  // 👈 EDIT THIS for your location
// const LOCAL_TIMEZONE = USER_TIMEZONE;  // 👈 EDIT THIS for your location
//
// For automatic detection (uses server timezone or environment variable):
const LOCAL_TIMEZONE = $env.TZ || 'Europe/Paris';  // 🟢 Default fallback
// To use user-defined timezone instead, comment out the above line

// Local date in YYYY-MM-DD format
const localDate = now.toLocaleDateString('sv-SE', { timeZone: LOCAL_TIMEZONE });

// Local datetime in YYYY-MM-DD_HH-MM-SS format
const localDateTime = now.toLocaleString('sv-SE', { 
  timeZone: LOCAL_TIMEZONE,
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit'
}).replace(' ', '_').replace(/:/g, '-');

// Local formatted time for display
const localTimeFormatted = now.toLocaleString('en-GB', { 
  timeZone: LOCAL_TIMEZONE,
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit'
});

const timestampUTC = now.toISOString().replace(/[:.]/g, '-').slice(0, 19); // 2025-01-20T09-30-45

console.log('🚀 USER-DEFINE TIMEZONE VARIABLES INITIALISED (Local timezone):');
console.log(`   🌍 Timezone: ${LOCAL_TIMEZONE}`);
console.log(`   📅 Local date: ${localDate}`);
console.log(`   📅 Local date/time: ${localDateTime}`);
console.log(`   🕐 Local time: ${localTimeFormatted}`);

// Create structure for time data output
const timeData = {
  nowUTC: now.toISOString(),        // UTC for calculations
  localDate: localDate,             // YYYY-MM-DD format
  localDateTime: localDateTime,     // YYY-MM-DD_HH-MM-SS format
  localTimeFormatted: localTimeFormatted, // Human readable
  localTimezone: LOCAL_TIMEZONE,         // For reference
  datePrefix: localDate,
  timestampUTC,
  startTime: now.toISOString()
}

// ==========================================
// 📝 WORKFLOW STANDARD CONFIGURATION
// ==========================================

const N8N_ADMIN_EMAIL = $env.N8N_ADMIN_EMAIL || 'youremail@world.com';
const WORKFLOW_NAME = $workflow.name;
const N8N_PROJECTS_DIR = $env.N8N_PROJECTS_DIR || '/files/n8n-projects-data'; // ⚠️ Your projects’ ROOT folder here
// projects-root-folder/
//   └── Your-project-folder-name/
//       ├── logs/
//       ├── reports/
//       ├── ...
//       └── [other project files]
const PROJECT_FOLDER_NAME = "Workflow-backups"; // ⚠️ Your project folder name
const PROJECT_ROOT_PATH = `${N8N_PROJECTS_DIR}/${PROJECT_FOLDER_NAME}`;
// const N8N_MEDIA_ROOT_PATH = $env.N8N_MEDIA_SHARED || '/files/n8n-media-shared'; // ⚠️ Your public folder, accessible from inet
// const mediaOutputFolder = "/output";
// const mediaTempFolder = "/temp";
// const N8N_FILE_SERVER_PURL = $env.N8N_FILE_SERVER_PURL || 'https://files.example.com'; // File serve public url

const LOGS_PATH = `${PROJECT_ROOT_PATH}/logs`;
// const logFileName = `${localDateTime2}-${WORKFLOW_NAME.replace(/[^a-zA-Z0-9]/g, '_')}_logs.json`;  // ⚠️ Your log file name
const logFileName = `${localDateTime}-backup_logs.json`;  // ⚠️ Your log file name
const logPathFileName = `${LOGS_PATH}/${logFileName}`;

// Configuration for report generation
const REPORTS_PATH = `${PROJECT_ROOT_PATH}/reports`;
const reportFileName = `${localDateTime}-report.txt`;
const reportPathFileName = `${REPORTS_PATH}/${reportFileName}`;

// Console output
console.log('🧾 STANDARD WORKFLOW VARIABLES INITIALISED:');
console.log(`   📁 Admin email: ${N8N_ADMIN_EMAIL}`);
console.log(`   📁 Workflow name: ${WORKFLOW_NAME}`);
console.log(`   📁 Projects folder: ${N8N_PROJECTS_DIR}`);
console.log(`   📁 Project folder name: ${PROJECT_FOLDER_NAME}`);
console.log(`   📁 Project root path: ${PROJECT_ROOT_PATH}`);
// console.log(`   📁 Media root path: ${N8N_MEDIA_ROOT_PATH}`);
// console.log(`   📁 File server public URL: ${N8N_FILE_SERVER_PURL}`);
console.log(`   📁 Log path: ${LOGS_PATH}`);
console.log(`   📁 Log file name: ${logFileName}`);
console.log(`   📁 Log file path: ${logPathFileName}`);
console.log(`   📁 Reports path: ${REPORTS_PATH}`);
console.log(`   📁 Report file name: ${reportFileName}`);
console.log(`   📁 Report file path: ${reportPathFileName}`);

// Create structure for workflow configuration output
const workflowConfig = {
  workflowStep: 'init',
  N8N_ADMIN_EMAIL,
  WORKFLOW_NAME,
  N8N_PROJECTS_DIR,
  PROJECT_FOLDER_NAME,
  PROJECT_ROOT_PATH,
  // N8N_MEDIA_ROOT_PATH,
  // mediaOutputFolder,
  // mediaTempFolder,
  // N8N_FILE_SERVER_PURL,
  LOGS_PATH,
  logFileName,
  logPathFileName,
  REPORTS_PATH,
  reportFileName,
  reportPathFileName
}

// ==========================================
// 📝 WORKFLOW CUSTOM CONFIGURATION
// ==========================================
// ⚠️  INSERT HERE: your workflow custom configuration variables

// Base backup path using your Docker and FTP volume configuration (folder must exist)
const BACKUP_FOLDER = $env.N8N_BACKUP_FOLDER || '/files/n8n-backups'; // ⚠️ Change the default value for your n8n backup folder
const FTP_BACKUP_FOLDER = $env.N8N_FTP_BACKUP_FOLDER || '/n8n-backups';
const FTPName = 'Your FTP Server Name'; // FTP server name for logging (display purposes only)

const credentials_backup_folder = "n8n-credentials"; // Credentials backup path

// Configuration for the backup process
const backupConfig = {
  datePrefix: localDate, // Prefix for all backup files
  fileNaming: 'name_only', // Options: 'name_only', 'id_only', 'name_and_id'
  maxRetries: 3,
  timeout: 30000,
  includeCredentials: false, // Security: Don't export credential data
  compression: false // Future enhancement
};

// Console output
console.log('🧾 CUSTOM WORKFLOW VARIABLES INITIALISED:');
console.log(`   💾 Backup folder: ${BACKUP_FOLDER}`);
console.log('      File prefix:', localDate);
console.log('      Timestamp (UTC):', timestampUTC);

const customConfig = {
  backupFolder: BACKUP_FOLDER,
  FTP_BACKUP_FOLDER,
  FTPName,
  credentials: credentials_backup_folder,
  ...backupConfig
}

// ==========================================
// 📊 OUTPUT DATA
// ==========================================

const initData = {
  timeData,
  workflowConfig,
  customConfig
};

return [{ json: initData }];

// ==========================================
// 🧹 FLEXIBLE FILENAME CLEANER
// ==========================================
// Purpose: Clean filename for cross-platform compatibility
// Usage: Can work with current input OR reference another node
//
// Recommended Configuration:
// **Node Settings**:
// * ☑️ **On Error**: Continue (using error output)
// * ☑️ **Error Workflow**: Your notification workflow
// The node stops at the first error and immediately triggers your notification system! 🚨

// ⚙️ CONFIGURATION
const SOURCE_FIELD = 'name';           // Field containing the filename
const SOURCE_NODE = 'Fetch Workflows';              // Set to node name like 'Fetch Workflows' OR null to use current input
                                       // Examples: 'Fetch Workflows', 'HTTP Request', 'Set'

// Get input items
const inputItems = $input.all();
const itemCount = inputItems.length;

console.log(`Flexible Filename Cleaner: Processing ${itemCount} item(s)`);
console.log(`Configuration: SOURCE_FIELD="${SOURCE_FIELD}", SOURCE_NODE=${SOURCE_NODE || 'current input'}`);

if (itemCount === 0) {
  console.error('No items to process');
  throw new Error('No items to process');
}

const outputItems = [];

inputItems.forEach((item, index) => {
  try {
    let originalFileName;
    let sourceDescription;

    // Determine where to get the filename from
    if (SOURCE_NODE) {
      // Get from specified node
      try {
        // Use the corresponding item from the source node (same index)
        const sourceItems = $(SOURCE_NODE).all();
        if (sourceItems[index]) {
          originalFileName = sourceItems[index].json[SOURCE_FIELD];
          sourceDescription = `${SOURCE_NODE}[${index}].${SOURCE_FIELD}`;
        } else {
          // Fallback to first item if index doesn't exist
          originalFileName = $(SOURCE_NODE).first().json[SOURCE_FIELD];
          sourceDescription = `${SOURCE_NODE}[0].${SOURCE_FIELD} (fallback)`;
        }
      } catch (nodeError) {
        const errorMsg = `Cannot access node '${SOURCE_NODE}': ${nodeError.message}`;
        console.error(errorMsg);
        throw new Error(errorMsg);
      }
    } else {
      // Get from current input item
      originalFileName = item.json[SOURCE_FIELD];
      sourceDescription = `current_input[${index}].${SOURCE_FIELD}`;
    }

    if (!originalFileName) {
      const errorMsg = `No filename found in ${sourceDescription}`;
      console.error(errorMsg);
      throw new Error(errorMsg);
    }

    console.log(`Item ${index + 1}/${itemCount}: "${originalFileName}" from ${sourceDescription}`);

    // Clean filename for cross-platform compatibility
    const cleanedFileName = originalFileName
      // Remove forbidden characters for Windows/Linux
      .replace(/[<>:"/\\|?*\x00-\x1F\x7F]/g, '_')
      // Replace multiple spaces/dots with single underscore
      .replace(/[\s.]+/g, '_')
      // Remove consecutive underscores
      .replace(/_+/g, '_')
      // Remove leading/trailing underscores
      .replace(/^_+|_+$/g, '')
      // Limit length to 180 chars
      .substring(0, 180);

    // Fallback if name becomes empty after cleaning
    const finalCleanedFileName = cleanedFileName || `file_${index + 1}`;

    console.log(`✅ Cleaned: "${finalCleanedFileName}"`);

    // Pass through all original data + add cleaned filename
    outputItems.push({
      json: {
        ...item.json,
        cleanedFileName: finalCleanedFileName
      },
      binary: item.binary || {}
    });

  } catch (error) {
    console.error(`❌ Error processing item ${index + 1}:`, error.message);

    // Log error and re-throw to trigger error workflow
    throw new Error(`Failed to process item ${index + 1}: ${error.message}`);
  }
});

console.log(`✅ Successfully processed ${outputItems.length} item(s)`);
return outputItems;

// Process file list from Execute Command and create items for each file
// ✅ Converts file list into individual items for Read Files node

// ⚠️ CONFIGURE THIS NODE WITH:
// SETTINGS > ON ERROR > CONTINUE (USING ERROR OUTPUT)

const initData = $('Init').first().json;
const commandResult = $input.first().json;
const exportResult = $('Export Credentials').first().json;

console.log('[Process File List] Command result:', commandResult);
console.log('[Process File List] Command stdout:', commandResult.stdout);

// Check if command was successful
if (commandResult.exitCode !== 0) {
  const errorMsg = `List files command failed with exit code ${commandResult.exitCode}`;
  console.error(`[Process File List] ${errorMsg}`);
  console.error(`[Process File List] Command stderr:`, commandResult.stderr);
  throw new Error(errorMsg);
}

// Parse the file list from stdout
const stdout = commandResult.stdout.trim();

if (!stdout || stdout === "No JSON files found") {
  console.log('[Process File List] No credentials files found');
  return [{ json: { workflowStep: 'no_credentials_files', message: 'No credentials files found' } }];
}

// Split file paths and filter out empty lines
const filePaths = stdout.split('\n').filter(path => path.trim().length > 0);

console.log(`[Process File List] Found ${filePaths.length} credentials file(s)`);

const outputItems = filePaths.map((fullPath, index) => {
  // Extract filename from full path
  const fileName = fullPath.split('/').pop();

  // Build FTP remote path
  const ftpPath = `${initData.customConfig.FTP_BACKUP_FOLDER}/${initData.customConfig.datePrefix}/${initData.customConfig.credentials}/${fileName}`;

  console.log(`[Process File List] File ${index + 1}: ${fileName}`);
  console.log(`  Local path: ${fullPath}`);
  console.log(`  FTP path: ${ftpPath}`);

  return {
    json: {
      fileName: fileName,
      localPath: fullPath,
      ftpPath: ftpPath,
      fileType: 'credentials_file',
      workflowStep: 'credentials_file_read',
      fileIndex: index + 1,
      totalFiles: filePaths.length,
      exportResult: {
        exitCode: exportResult.exitCode,
        stdout: exportResult.stdout,
        stderr: exportResult.stderr
      }
    }
  };
});

console.log(`[Process File List] ✅ Created ${outputItems.length} items for file reading`);

return outputItems;

// FTP Upload Results Logger for Credentials Files
// ✅ Processes FTP upload results from individual credentials files and creates comprehensive logging data
// ✅ Enhanced error handling for FTP connection timeouts and server errors

// ⚠️ CONFIGURE THIS NODE WITH:
// SETTINGS > ON ERROR > CONTINUE (USING ERROR OUTPUT)

const allFtpResults = $input.all();
const initData = $('Init').first().json;

console.log('[FTP Logger] Processing FTP upload results for credentials files...');
console.log(`[FTP Logger] Received ${allFtpResults.length} FTP result item(s)`);

const ftpUploadResults = {
  timestamp: new Date().toISOString(),
  localTimestamp: new Date().toLocaleString('en-GB', { timeZone: initData.timeData.timezone }),
  totalFiles: allFtpResults.length,
  successfulUploads: 0,
  failedUploads: 0,
  uploads: []
};

// Process each FTP result
allFtpResults.forEach((result, index) => {
  try {
    // Handle different result structures (success vs error outputs)
    let uploadData;
    let isConnectionError = false;
    let connectionErrorMessage = null;

    // Check if this is an error result from FTP node
    if (result.error) {
      // This comes from the error output of FTP node
      isConnectionError = true;
      connectionErrorMessage = result.error;
      uploadData = result.json || {};
      console.log(`[FTP Logger] FTP node error detected: ${connectionErrorMessage}`);
    } else if (result.json && result.json.error) {
      // Error embedded in JSON response
      isConnectionError = true;
      connectionErrorMessage = result.json.error;
      uploadData = result.json;
      console.log(`[FTP Logger] FTP JSON error detected: ${connectionErrorMessage}`);
    } else {
      // Normal success/failure response
      uploadData = result.json || {};
    }

    // Determine if upload was successful
    const isSuccess = !isConnectionError && !uploadData.error && uploadData.success !== false;

    // Extract file information with fallbacks
    const fileName = uploadData.fileName || uploadData.path || `credentials_file_${index + 1}`;
    const ftpPath = uploadData.ftpPath || uploadData.path || 'unknown';

    const uploadLog = {
      fileName: fileName,
      fileType: uploadData.fileType || 'credentials_file',
      localPath: uploadData.localPath || 'unknown',
      ftpPath: ftpPath,
      success: isSuccess,
      uploadTime: new Date().toISOString(),
      error: connectionErrorMessage || uploadData.error || null,
      ftpResponse: uploadData.response || null,
      fileSize: uploadData.fileSize || null,
      fileIndex: uploadData.fileIndex || index + 1,
      connectionError: isConnectionError
    };

    if (isSuccess) {
      ftpUploadResults.successfulUploads++;
      console.log(`[FTP Logger] ✅ Successfully uploaded: ${uploadLog.fileName} (${uploadLog.fileIndex}/${uploadData.totalFiles || ftpUploadResults.totalFiles})`);
    } else {
      ftpUploadResults.failedUploads++;
      if (isConnectionError) {
        console.error(`[FTP Logger] 🔌 Connection error for: ${uploadLog.fileName} - ${connectionErrorMessage}`);
      } else {
        console.error(`[FTP Logger] ❌ Failed to upload: ${uploadLog.fileName} (${uploadLog.fileIndex}/${uploadData.totalFiles || ftpUploadResults.totalFiles})`);
      }
      if (uploadLog.error) {
        console.error(`[FTP Logger] Error details: ${uploadLog.error}`);
      }
    }

    ftpUploadResults.uploads.push(uploadLog);

  } catch (error) {
    console.error(`[FTP Logger] Error processing result ${index + 1}:`, error.message);

    // Add error entry for processing failures
    ftpUploadResults.uploads.push({
      fileName: `unknown_file_${index + 1}`,
      fileType: 'credentials_file',
      localPath: 'unknown',
      ftpPath: 'unknown',
      success: false,
      error: `Processing error: ${error.message}`,
      uploadTime: new Date().toISOString(),
      fileIndex: index + 1,
      connectionError: false
    });

    ftpUploadResults.failedUploads++;
  }
});

// Create simplified summary
const connectionErrors = ftpUploadResults.uploads.filter(upload => upload.connectionError);
const hasConnectionErrors = connectionErrors.length > 0;

// Create simplified summary
const ftpSummary = {
  overallSuccess: ftpUploadResults.failedUploads === 0,
  summary: hasConnectionErrors ? 
    `FTP server connection failed - credentials files could not be uploaded due to server connectivity issues` :
    `${ftpUploadResults.successfulUploads}/${ftpUploadResults.totalFiles} credentials files uploaded successfully`
};

console.log('[FTP Logger] Credentials Upload Summary:');
console.log(`  Total credentials files: ${ftpUploadResults.totalFiles}`);
console.log(`  Successful uploads: ${ftpUploadResults.successfulUploads}`);
console.log(`  Failed uploads: ${ftpUploadResults.failedUploads}`);

if (hasConnectionErrors) {
  console.log('[FTP Logger] 🔌 FTP server connection failed');
}

// Add summary to results
ftpUploadResults.summary = ftpSummary;

// Create output data that will be merged with Backup Summary
const credentialsFtpLog = {
  credentialsFtpUpload: ftpUploadResults
};

console.log('[FTP Logger] ✅ Credentials FTP upload logging completed');

return [{ json: credentialsFtpLog }];

